const express = require('express');
const cors = require('cors');
const db = require('./db');

const app = express();
const port = process.env.PORT || 5000;

// Enhanced CORS configuration for mobile and network access
const corsOptions = {
  origin: true, // Allow all origins (safe for development)
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  optionsSuccessStatus: 200
};

app.use(cors(corsOptions));
app.use(express.json());

// Import routes
const authRoutes = require('./routes/auth');
const sessionRoutes = require('./routes/sessions');
const transcribeRoutes = require('./routes/transcribe');

app.use('/api/auth', authRoutes);
app.use('/api/sessions', sessionRoutes);
app.use('/api/transcribe', transcribeRoutes);

app.get('/', (req, res) => {
  res.send('Dementia Detection API is running');
});

// Listen on all network interfaces (0.0.0.0) for mobile device access
app.listen(port, '0.0.0.0', () => {
  console.log(`Server running on port ${port} - accessible from network devices`);
});
